def exec_evaluation(turn_data):
    try:
        # 获取实际输出和参考输出
        actual_text = turn_data["turn"]["eval_target"]["actual_output"]["text"]
        reference_text = turn_data["turn"]["eval_set"]["reference_output"]["text"]

        # 比较文本相似性或相等性
        is_equal = actual_text.strip() == reference_text.strip()
        score = 1.0 if is_equal else 0.0

        if is_equal:
            status = "匹配"
        else:
            status = "不匹配"
        reason = f"实际输出与参考输出{status}。实际输出: '{actual_text}', 参考输出: '{reference_text}'"

        return EvalOutput(score=score, reason=reason, err_msg="")

    except KeyError as e:
        return EvalOutput(score=0.0, reason=f"字段路径未找到: {e}", err_msg=str(e))
    except Exception as e:
        return EvalOutput(score=0.0, reason=f"评估失败: {e}", err_msg=str(e))
